def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 3:
            base_score = 3000 + 100 * (ratio - 3) ** 4 - 25 * np.sqrt(ratio)
        elif ratio > 2:
            base_score = 1800 + 40 * (ratio - 2) ** 3 - 15 * np.log(ratio + 1)
        elif ratio > 1:
            base_score = 900 + 30 * (ratio - 1) ** 2 + 5 * np.sin(ratio * np.pi)
        else:
            if ratio > 0.95:
                base_score = 100 * ratio + 25 + 5 * (capacity % 7)
            elif ratio > 0.8:
                base_score = 60 * ratio + 20 + 7 * (i % 4)
            elif ratio > 0.5:
                base_score = 25 * ratio + 10 + (capacity % 3) * 4
            else:
                base_score = 8 * ratio + 2 + (i % 2) * 6
            if capacity < 3:
                base_score += 30 - ratio * 10
            elif capacity < 15:
                base_score += 15 + 2 * i
            elif capacity > 150:
                base_score -= 20 + (item % 5)
        modifier = 1.0
        if i % 4 == 0:
            modifier += 0.2
            if ratio < 0.4:
                modifier += 0.07
        elif i % 4 == 1:
            modifier -= 0.12
            if ratio > 1.4:
                modifier -= 0.08
        elif i % 4 == 2:
            modifier += 0.1
            if capacity % 5 == 0:
                modifier += 0.05
        else:
            modifier -= 0.05
            if ratio > 0.7 and ratio < 1.1:
                modifier += 0.03
        adjusted_score = base_score * modifier
        if i % 6 == 0:
            sum_neighbors = 0
            count = 0
            for j in range(max(0, i-3), min(len(bins), i+4)):
                if j != i and bins[j] > 0:
                    diff = abs(item - bins[j])
                    weight = 1 / (abs(i - j) + 1)
                    sum_neighbors += diff * weight
                    count += weight
            if count > 0:
                weighted_avg_diff = sum_neighbors / count
                if weighted_avg_diff < capacity * 0.4:
                    adjusted_score *= 0.75
                else:
                    adjusted_score *= 1.3
        if i % 7 == 3:
            primeness_mod = 0.03 if is_prime(int(capacity)) else -0.02
            adjusted_score *= (1 + primeness_mod)
        priorities[i] = adjusted_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fallback = 0
    else:
        fallback = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = fallback + 200
    for i in range(len(priorities)):
        if priorities[i] < 25:
            increment = 15 * (item / (bins[i] + 2)) + (i % 5)
            priorities[i] += increment
    for _ in range(2):
        for i in range(1, len(priorities)-1):
            if priorities[i] > priorities[i-1] and priorities[i] > priorities[i+1]:
                priorities[i] *= 0.9
            elif priorities[i] < priorities[i-1] and priorities[i] < priorities[i+1]:
                priorities[i] *= 1.1
    return priorities
